/**
 * Validation helper module
 * Provides reusable field validators and a runner that collects all errors.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Individual field validators.
 * Each returns an error string on failure, or null on success.
 */
const validators = {
  /**
   * Ensure a value is present (not undefined, null, or empty string).
   */
  required(value, fieldName) {
    if (value === undefined || value === null || value === '') {
      return `"${fieldName}" is required`;
    }
    return null;
  },

  /**
   * Ensure a value is a finite number (or a string that coerces to one).
   * Useful for validating route params like :id.
   */
  numeric(value, fieldName) {
    if (value === undefined || value === null) return null; // let required() catch absence
    const num = Number(value);
    if (!Number.isFinite(num)) {
      return `"${fieldName}" must be a numeric value`;
    }
    return null;
  },

  /**
   * Ensure a value is a non-empty string (type check only, length handled separately).
   */
  string(value, fieldName) {
    if (value === undefined || value === null) return null; // let required() catch absence
    if (typeof value !== 'string') {
      return `"${fieldName}" must be a string`;
    }
    return null;
  },

  /**
   * Ensure a string value matches a valid e-mail format and is ≤ 254 chars.
   */
  email(value, fieldName) {
    if (value === undefined || value === null) return null;
    if (typeof value !== 'string') return null; // string() will already report the type error
    if (value.length > 254) {
      return `"${fieldName}" must be 254 characters or fewer`;
    }
    if (!EMAIL_REGEX.test(value)) {
      return `"${fieldName}" must be a valid email address`;
    }
    return null;
  },

  /**
   * Ensure a string value's length is within [min, max] (inclusive).
   */
  length(value, fieldName, min, max) {
    if (value === undefined || value === null) return null;
    if (typeof value !== 'string') return null; // string() will already report the type error
    if (value.length < min || value.length > max) {
      return `"${fieldName}" must be between ${min} and ${max} characters`;
    }
    return null;
  },
};

/**
 * Run a list of validation checks and collect every error message.
 *
 * @param {Array<Function>} checks - Zero-argument functions that return an error
 *   string or null.  Build them by partially applying validators above.
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validate(checks) {
  const errors = checks
    .map((check) => check())
    .filter((err) => err !== null);

  return { valid: errors.length === 0, errors };
}

/**
 * Convenience: send a 400 JSON response with the collected error list.
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 */
function sendValidationError(res, errors) {
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = { validators, validate, sendValidationError };

