/**
 * Validation helper module.
 *
 * Each validate* function returns an array of error strings.
 * An empty array means the input is valid.
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID supplied as a route parameter (always a string from req.params).
 * Rules: must be present, must be a whole positive number.
 *
 * @param {*} id - raw value from req.params.id
 * @returns {string[]} array of validation error messages
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no point in further checks
  }

  const num = Number(id);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the `name` field from a request body.
 * Rules: required, must be a string, length 1-100 characters.
 *
 * @param {*} name - raw value from req.body.name
 * @returns {string[]} array of validation error messages
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors; // length checks are meaningless on non-strings
  }

  if (name.length < 1) {
    errors.push('name must be at least 1 character long');
  } else if (name.length > 100) {
    errors.push('name must be no more than 100 characters long');
  }

  return errors;
}

/**
 * Validate the `email` field from a request body.
 * Rules: required, must be a string, valid email format, max 254 characters.
 *
 * @param {*} email - raw value from req.body.email
 * @returns {string[]} array of validation error messages
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > 254) {
    errors.push('email must be no more than 254 characters long');
  }

  if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate a complete user body (name + email).
 * Collects errors from both fields and returns them together.
 *
 * @param {object} body - req.body
 * @returns {string[]} combined array of validation error messages
 */
function validateUserBody(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate a partial user body for PATCH-style updates where both fields are
 * optional but at least one must be present, and any supplied field must still
 * pass its own rules.
 *
 * @param {object} body - req.body
 * @returns {string[]} array of validation error messages
 */
function validatePartialUserBody(body) {
  const errors = [];

  const hasName  = body.name  !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided');
    return errors;
  }

  if (hasName)  errors.push(...validateName(body.name));
  if (hasEmail) errors.push(...validateEmail(body.email));

  return errors;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  validatePartialUserBody,
};

