// validation.js — reusable input-validation helpers

'use strict';

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user id supplied via a route parameter.
 * Returns an array of error strings (empty = valid).
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no point in further checks
  }

  // Route params arrive as strings; coerce and check
  if (!/^\d+$/.test(String(id)) || Number(id) <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate the body fields for creating a user.
 * Both `name` and `email` are required.
 */
function validateCreateUser(body) {
  const errors = [];

  // --- name ---
  if (body.name === undefined || body.name === null) {
    errors.push('name is required');
  } else if (typeof body.name !== 'string') {
    errors.push('name must be a string');
  } else if (body.name.trim().length < 1) {
    errors.push('name must be at least 1 character');
  } else if (body.name.length > 100) {
    errors.push('name must be at most 100 characters');
  }

  // --- email ---
  if (body.email === undefined || body.email === null) {
    errors.push('email is required');
  } else if (typeof body.email !== 'string') {
    errors.push('email must be a string');
  } else if (body.email.length > 254) {
    errors.push('email must be at most 254 characters');
  } else if (!EMAIL_REGEX.test(body.email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the body fields for updating a user.
 * At least one of `name` / `email` must be present; both are optional,
 * but when provided they must satisfy the same rules as on creation.
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName  = body.name  !== undefined && body.name  !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one of name or email must be provided');
    return errors;
  }

  // --- name (optional on update) ---
  if (hasName) {
    if (typeof body.name !== 'string') {
      errors.push('name must be a string');
    } else if (body.name.trim().length < 1) {
      errors.push('name must be at least 1 character');
    } else if (body.name.length > 100) {
      errors.push('name must be at most 100 characters');
    }
  }

  // --- email (optional on update) ---
  if (hasEmail) {
    if (typeof body.email !== 'string') {
      errors.push('email must be a string');
    } else if (body.email.length > 254) {
      errors.push('email must be at most 254 characters');
    } else if (!EMAIL_REGEX.test(body.email)) {
      errors.push('email must be a valid email address');
    }
  }

  return errors;
}

/**
 * Express middleware factory — validates a request and responds with 400
 * if any errors are found.
 *
 * @param  {Function} validatorFn  One of the validate* functions above.
 * @param  {'body'|'params'} source  Where to pull data from.
 */
function validate(validatorFn, source = 'body') {
  return (req, res, next) => {
    const data   = source === 'params' ? req.params : req.body;
    const errors = validatorFn(data);

    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }

    next();
  };
}

module.exports = {
  validateId,
  validateCreateUser,
  validateUpdateUser,
  validate,
};

