/**
 * Validation helper module.
 *
 * Provides individual field validators and a `validate()` runner that
 * collects every failing rule and returns a single, descriptive error
 * message array — keeping route handlers clean.
 */

'use strict';

// ---------------------------------------------------------------------------
// Individual validators
// Each returns a string describing the problem, or null when the value is OK.
// ---------------------------------------------------------------------------

/**
 * Assert that a value is present (not undefined, null, or empty string).
 * @param {*}      value
 * @param {string} fieldName
 * @returns {string|null}
 */
function required(value, fieldName) {
  if (value === undefined || value === null || value === '') {
    return `"${fieldName}" is required`;
  }
  return null;
}

/**
 * Assert that a value is a finite number (or a string that coerces to one).
 * Intended for id-style parameters that arrive as URL path segments (strings).
 * @param {*}      value
 * @param {string} fieldName
 * @returns {string|null}
 */
function numeric(value, fieldName) {
  if (value === undefined || value === null) return null; // let required() handle absence
  const n = Number(value);
  if (!Number.isFinite(n)) {
    return `"${fieldName}" must be a numeric value`;
  }
  return null;
}

/**
 * Assert that a value is a non-null string.
 * @param {*}      value
 * @param {string} fieldName
 * @returns {string|null}
 */
function isString(value, fieldName) {
  if (value === undefined || value === null) return null; // let required() handle absence
  if (typeof value !== 'string') {
    return `"${fieldName}" must be a string`;
  }
  return null;
}

/**
 * Assert that a string's length falls within [min, max] (inclusive).
 * Silently skips non-strings so it composes cleanly with isString().
 * @param {*}      value
 * @param {string} fieldName
 * @param {number} min
 * @param {number} max
 * @returns {string|null}
 */
function stringLength(value, fieldName, min, max) {
  if (typeof value !== 'string') return null;
  if (value.length < min || value.length > max) {
    return `"${fieldName}" must be between ${min} and ${max} characters`;
  }
  return null;
}

/**
 * Assert that a string matches a valid e-mail format (RFC 5321 practical subset).
 * Silently skips non-strings so it composes cleanly with isString().
 * @param {*}      value
 * @param {string} fieldName
 * @returns {string|null}
 */
function emailFormat(value, fieldName) {
  if (typeof value !== 'string') return null;
  // Local-part @ domain, domain must contain at least one dot
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return `"${fieldName}" must be a valid email address`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Validation runner
// ---------------------------------------------------------------------------

/**
 * Run an array of validator functions and collect all error messages.
 *
 * Each entry in `rules` is a zero-argument function that returns either a
 * string (error message) or null (pass).  This lets callers use closures to
 * bind values and field names:
 *
 *   const errors = validate([
 *     () => required(body.name, 'name'),
 *     () => isString(body.name, 'name'),
 *     () => stringLength(body.name, 'name', 1, 100),
 *   ]);
 *
 * @param {Array<() => string|null>} rules
 * @returns {string[]}  Array of error messages; empty means all rules passed.
 */
function validate(rules) {
  const errors = [];
  for (const rule of rules) {
    const msg = rule();
    if (msg !== null) {
      errors.push(msg);
    }
  }
  return errors;
}

// ---------------------------------------------------------------------------
// Pre-built rule sets for common field combos
// ---------------------------------------------------------------------------

/**
 * Standard rules for a user `id` arriving as a URL path parameter (string).
 * @param {*} value
 * @returns {Array<() => string|null>}
 */
function idRules(value) {
  return [
    () => required(value, 'id'),
    () => numeric(value, 'id'),
  ];
}

/**
 * Standard rules for a `name` field in a request body.
 * @param {*} value
 * @returns {Array<() => string|null>}
 */
function nameRules(value) {
  return [
    () => required(value, 'name'),
    () => isString(value, 'name'),
    () => stringLength(value, 'name', 1, 100),
  ];
}

/**
 * Standard rules for an `email` field in a request body.
 * @param {*} value
 * @returns {Array<() => string|null>}
 */
function emailRules(value) {
  return [
    () => required(value, 'email'),
    () => isString(value, 'email'),
    () => stringLength(value, 'email', 1, 254),
    () => emailFormat(value, 'email'),
  ];
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // primitives – useful when writing custom rule sets
  required,
  numeric,
  isString,
  stringLength,
  emailFormat,
  // runner
  validate,
  // pre-built rule sets
  idRules,
  nameRules,
  emailRules,
};

