/**
 * Validation helper module.
 * Each validator returns an array of error message strings (empty = valid).
 * The middleware factory `validate()` collects all errors and sends a 400
 * response when any are found, keeping route handlers clean.
 */

'use strict';

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

/**
 * Ensures a value is present (not undefined, null, or empty string).
 * @param {*}      value - The value to test.
 * @param {string} field - Field name used in the error message.
 * @returns {string[]} Array of error messages (empty if valid).
 */
function validateRequired(value, field) {
  if (value === undefined || value === null || value === '') {
    return [`"${field}" is required`];
  }
  return [];
}

/**
 * Ensures a value is a finite number (or a string that encodes one).
 * Useful for URL params, which arrive as strings.
 * @param {*}      value - The value to test.
 * @param {string} field - Field name used in the error message.
 * @returns {string[]} Array of error messages (empty if valid).
 */
function validateNumeric(value, field) {
  if (value === undefined || value === null) return [];          // let validateRequired handle absence
  const num = Number(value);
  if (!Number.isFinite(num)) {
    return [`"${field}" must be a numeric value`];
  }
  return [];
}

/**
 * Ensures a value is a non-null string.
 * @param {*}      value - The value to test.
 * @param {string} field - Field name used in the error message.
 * @returns {string[]} Array of error messages (empty if valid).
 */
function validateString(value, field) {
  if (value === undefined || value === null) return [];          // let validateRequired handle absence
  if (typeof value !== 'string') {
    return [`"${field}" must be a string`];
  }
  return [];
}

/**
 * Ensures a string value falls within [min, max] length bounds.
 * Skips the check when the value is absent or not a string (other validators
 * are responsible for those cases).
 * @param {*}      value - The value to test.
 * @param {string} field - Field name used in the error message.
 * @param {number} min   - Minimum allowed length (inclusive).
 * @param {number} max   - Maximum allowed length (inclusive).
 * @returns {string[]} Array of error messages (empty if valid).
 */
function validateLength(value, field, min, max) {
  if (typeof value !== 'string') return [];
  if (value.length < min || value.length > max) {
    return [`"${field}" must be between ${min} and ${max} characters`];
  }
  return [];
}

/**
 * Ensures a string value matches a basic RFC 5321-compatible email pattern.
 * Skips the check when the value is absent or not a string.
 * @param {*}      value - The value to test.
 * @param {string} field - Field name used in the error message.
 * @returns {string[]} Array of error messages (empty if valid).
 */
function validateEmail(value, field) {
  if (typeof value !== 'string') return [];
  // local@domain.tld — allows common special chars in local part
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(value)) {
    return [`"${field}" must be a valid email address`];
  }
  return [];
}

// ---------------------------------------------------------------------------
// Reusable rule sets for common fields
// ---------------------------------------------------------------------------

/**
 * Full rule set for a *required* `name` field.
 * Rules: required · must be string · length 1–100.
 */
function rulesForRequiredName(value) {
  return [
    ...validateRequired(value, 'name'),
    ...validateString(value, 'name'),
    ...validateLength(value, 'name', 1, 100),
  ];
}

/**
 * Rule set for an *optional* `name` field (present but possibly empty object key).
 * Rules: must be string · length 1–100 (only when the key is actually provided).
 */
function rulesForOptionalName(value) {
  if (value === undefined) return [];
  return [
    ...validateRequired(value, 'name'),
    ...validateString(value, 'name'),
    ...validateLength(value, 'name', 1, 100),
  ];
}

/**
 * Full rule set for a *required* `email` field.
 * Rules: required · must be string · valid email format · max 254 chars.
 */
function rulesForRequiredEmail(value) {
  return [
    ...validateRequired(value, 'email'),
    ...validateString(value, 'email'),
    ...validateEmail(value, 'email'),
    ...validateLength(value, 'email', 1, 254),
  ];
}

/**
 * Rule set for an *optional* `email` field.
 * Rules: must be string · valid email format · max 254 chars (only when provided).
 */
function rulesForOptionalEmail(value) {
  if (value === undefined) return [];
  return [
    ...validateRequired(value, 'email'),
    ...validateString(value, 'email'),
    ...validateEmail(value, 'email'),
    ...validateLength(value, 'email', 1, 254),
  ];
}

/**
 * Rule set for a numeric `id` URL parameter.
 * Rules: required · must be numeric.
 */
function rulesForId(value) {
  return [
    ...validateRequired(value, 'id'),
    ...validateNumeric(value, 'id'),
  ];
}

// ---------------------------------------------------------------------------
// Middleware factory
// ---------------------------------------------------------------------------

/**
 * Returns an Express middleware function that runs `rulesFn` and — when any
 * errors are found — responds with HTTP 400 and a JSON body listing every
 * failed validation.
 *
 * Usage:
 *   app.post('/users', validate((req) => [
 *     ...rulesForRequiredName(req.body.name),
 *     ...rulesForRequiredEmail(req.body.email),
 *   ]), handler);
 *
 * @param {(req: import('express').Request) => string[]} rulesFn
 *   A function that receives the Express request and returns an array of
 *   error strings produced by the validator helpers above.
 * @returns {import('express').RequestHandler}
 */
function validate(rulesFn) {
  return (req, res, next) => {
    const errors = rulesFn(req);
    if (errors.length > 0) {
      return res.status(400).json({
        error: 'Validation failed',
        details: errors,
      });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Low-level validators (handy for one-off rules)
  validateRequired,
  validateNumeric,
  validateString,
  validateLength,
  validateEmail,
  // Reusable field rule sets
  rulesForId,
  rulesForRequiredName,
  rulesForOptionalName,
  rulesForRequiredEmail,
  rulesForOptionalEmail,
  // Middleware factory
  validate,
};

