/**
 * Validation helper module.
 *
 * Each validator returns an array of error message strings.
 * An empty array means the value passed all checks.
 *
 * The high-level helpers (validateRouteId, validateCreateUser,
 * validateUpdateUser) collect errors from every relevant field and return
 * them together so callers can surface all failures in a single 400 response.
 */

'use strict';

// ---------------------------------------------------------------------------
// Field-level validators
// ---------------------------------------------------------------------------

/**
 * Validate a URL-parameter id.
 * Must be present and consist solely of digits (coerced to a positive integer).
 *
 * @param {*} value - The raw value from req.params.id
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateId(value) {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push('id is required');
    return errors; // no point checking further
  }

  if (typeof value !== 'string' && typeof value !== 'number') {
    errors.push('id must be a numeric value');
    return errors;
  }

  // Accept strings that look like positive integers (no leading zeros except "0" itself)
  if (!/^\d+$/.test(String(value))) {
    errors.push('id must be a numeric value (positive integer)');
    return errors;
  }

  const numeric = Number(value);
  if (!Number.isInteger(numeric) || numeric <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a user name.
 * Must be a non-empty string with 1–100 characters.
 *
 * @param {*} value - The raw value from the request body
 * @param {boolean} [required=true] - Whether the field is mandatory
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateName(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = value.trim();

  if (trimmed.length < 1) {
    errors.push('name must not be empty');
  } else if (trimmed.length > 100) {
    errors.push(`name must be at most 100 characters (received ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an email address.
 * Must be a string matching a standard email pattern and ≤ 254 characters
 * (RFC 5321 maximum length for an email address).
 *
 * @param {*} value - The raw value from the request body
 * @param {boolean} [required=true] - Whether the field is mandatory
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateEmail(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  // RFC 5321 §4.5.3.1.3 caps the total length at 254 characters
  if (value.length > 254) {
    errors.push('email must be at most 254 characters');
  }

  // Practical email regex: local@domain.tld
  // Covers the vast majority of real-world addresses without false negatives.
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Request-level validators (compose field validators)
// ---------------------------------------------------------------------------

/**
 * Validate the :id route parameter.
 *
 * @param {object} params - req.params
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateRouteId(params) {
  const errors = validateId(params.id);
  return { valid: errors.length === 0, errors };
}

/**
 * Validate the body of a POST /users request.
 * Both `name` and `email` are required.
 *
 * @param {object} body - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateCreateUser(body) {
  const errors = [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
  return { valid: errors.length === 0, errors };
}

/**
 * Validate the body of a PUT /users/:id request.
 * At least one of `name` or `email` must be provided; each is validated when present.
 *
 * @param {object} params - req.params
 * @param {object} body   - req.body
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateUpdateUser(params, body) {
  const errors = [
    ...validateId(params.id),
  ];

  const hasName  = body.name  !== undefined && body.name  !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one of name or email must be provided for an update');
  } else {
    if (hasName)  errors.push(...validateName(body.name,   true));
    if (hasEmail) errors.push(...validateEmail(body.email, true));
  }

  return { valid: errors.length === 0, errors };
}

// ---------------------------------------------------------------------------
// Express middleware factory
// ---------------------------------------------------------------------------

/**
 * Return an Express middleware that runs `validatorFn` and short-circuits
 * with a 400 JSON response when validation fails.
 *
 * Usage:
 *   router.post('/users', validate(req => validateCreateUser(req.body)), handler);
 *
 * @param {function(import('express').Request): { valid: boolean, errors: string[] }} validatorFn
 * @returns {import('express').RequestHandler}
 */
function validate(validatorFn) {
  return (req, res, next) => {
    const result = validatorFn(req);
    if (!result.valid) {
      return res.status(400).json({
        error: 'Validation failed',
        details: result.errors,
      });
    }
    next();
  };
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  // Field-level (useful for unit tests and custom compositions)
  validateId,
  validateName,
  validateEmail,

  // Request-level
  validateRouteId,
  validateCreateUser,
  validateUpdateUser,

  // Middleware factory
  validate,
};
